import { StateEnums } from './../../enums/state-enums';
import { Component, Inject } from '@angular/core';
import { IonicPage, NavController, NavParams } from 'ionic-angular';
import { StorageData } from '../../utils/storageData';
import { Utils } from '../../utils/utils';
import { ServiceRequestProvider } from '../../providers/service-request/service-request';

/**
 * Generated class for the Addition22Page page.
 *
 * See https://ionicframework.com/docs/components/#navigation for more info on
 * Ionic pages and navigation.
 */

@Component({
  selector: 'page-addition22',
  templateUrl: 'addition22.html',
  providers: [Utils, ServiceRequestProvider, StorageData]
})
export class Addition22Page {

  stateEnums: any;

  aciklama: any = "";
  deviceInfo: any = "";
  sr: any;

  constructor(public navCtrl: NavController,
    public navParams: NavParams,
    public utils: Utils,
    public serviceRequestProvider: ServiceRequestProvider,
    public storage: StorageData, @Inject('apiUrl') private apiUrl) {
    this.sr = navParams.data.sr;
    this.stateEnums = StateEnums;
    this.storage.get("deviceInfo", (deviceInfo) => {
      this.deviceInfo = "\n ( Cihaz Bilgi : " + deviceInfo.mobilDeviceInfo + " )";

    });
  }

  ionViewDidLoad() {
    console.log('ionViewDidLoad Ek22Page');
  }

  ek22Save() {
    let me = this;
    this.utils.doConfirm("EK 22", "Kayıt etmek istediğinizden emin misiniz ?", function () {
      let select = "?$select=Durum";
      let seoUrl = "HelpDeskFMS_Module_ServisIstegi(guid'" + me.sr["Oid"] + "')" + select;
      me.utils.loadingPresent("Servis isteğinin son durumu kontrol ediliyor..");
      me.serviceRequestProvider.getServiceRequest(seoUrl, null).subscribe(res => {
        me.utils.loadingDismiss();
        let durum = res["Durum"];
        if (durum === 30 || durum === 40 || durum === 41 || durum === 42 || durum === 62 || durum === 70 || durum === 72) {
          seoUrl = "HelpDeskFMS_Module_Islem";
          let body = {
            "odata.type": "XafDataService.HelpDeskFMS_Module_SE_EK22",
            "IlgiliServisIstegi@odata.bind": me.apiUrl + "HelpDeskFMS_Module_ServisIstegi(guid'" + me.sr["Oid"] + "')",
            "Durum": 80,
            "Aciklama": me.aciklama
          };
          let message = "Ek-22 gönderilsin mi ?";
          me.utils.doConfirm("Ek-22", message, function () {
            me.utils.loadingPresent("Lütfen Bekleyiniz...");
            me.serviceRequestProvider.postServiceRequest(seoUrl, body).subscribe(p => {
              me.utils.loadingDismiss();
              me.utils.doAlertConfirm("İşlem başarılı...", function () {
                me.utils.loadingDismiss();
                me.navCtrl.pop();
                me.utils.processOK();
              });
            }, error => {
              me.utils.loadingDismiss();
              //me.utils.doAlert("Bağlantınızı kontrol ediniz...");
            });
          })
        }
        else {
          let message = "Son Durumu <b>'" + me.stateEnums["state" + durum] + "'</b> olan servis isteği üzerinde '<b>Ek-22</b>' işlemi yapamazsınız!'"
          me.utils.doAlert(message);
        }
      }, error => {
        me.utils.loadingDismiss();
      });
    });

  }

}



