import { SamplePortagePopoverPage } from './../sample-portage-popover/sample-portage-popover';
import { CreateSamplePortagePage } from './../create-sample-portage/create-sample-portage';
import { BarcodeScanner } from '@ionic-native/barcode-scanner';
import { Component, ViewChild, ElementRef, ChangeDetectorRef, Inject } from '@angular/core';
import {
  NavController,
  NavParams,
  LoadingController,
  ToastController,
  MenuController,
  ModalController,
  Content,
  Platform,
  App,
  InfiniteScroll,
  Events,
  PopoverController
} from 'ionic-angular';

import { ServiceRequestProvider } from '../../providers/service-request/service-request';
import { Utils } from '../../utils/utils';
import { GlobalVariables } from '../../globalVariables/global-variables';
import { StorageData } from '../../utils/storageData';




@Component({
  selector: 'page-sample-portage',
  templateUrl: 'sample-portage.html',
  providers: [ServiceRequestProvider, Utils, GlobalVariables, BarcodeScanner, StorageData]
})
export class SamplePortagePage {

  @ViewChild('scrollContentNumune') content: Content;
  @ViewChild('headerElementNumune') headerElement: ElementRef;
  @ViewChild('scrollFabButtonNumune') myElement: ElementRef;

  stateEnums: any;
  typeEnums: any;
  hydpEnums: any;
  userInfo: any;
  process: any = "OK";

  constructor(public navCtrl: NavController,
    public navParams: NavParams,
    public loadingCtrl: LoadingController,
    public cdr: ChangeDetectorRef,
    public toastCtrl: ToastController,
    public menu: MenuController,
    public modalCtrl: ModalController,
    public serviceRequestProvider: ServiceRequestProvider,
    public utils: Utils, public storage: StorageData,
    public platform: Platform,
    public popoverCtrl: PopoverController,
    public globalVariables: GlobalVariables, public app: App,
    public barcodeScanner: BarcodeScanner,
    public events: Events, @Inject('apiUrl') private apiUrl) {


    this.events.subscribe('afterProcessOK', (data) => {
      if (data === this.process) {
        this.process = "FINISH";
        return this.getSamplePortageList();
      }
    });

  }


  samplePortageList: any[] = [];
  copy: any[] = [];
  shouldEnableScrolling: boolean = false;
  limitToFirst: number = 0;
  top: number = 10;
  searchInput: any;
  selectedPortage: any;

  changePipe: string = "Tarih";
  tempPipe: string = "-Tarih";
  ascDesc: string = "desc";
  pipeMesaj: string = "Açılış Tarihine Göre ⬇️";
  shortIcon: string = "takvim-down.png";
  arrowSide: string = "md-arrow-round-down";
  arrowSideColor: string = "#36495e";



  ngAfterViewInit() {
    this.utils.scrollContentFabControl(this.content, this.myElement);
  }

  scrollTop(val) {
    this.content.scrollToTop(val);
  }







  ionViewWillEnter() {
    setTimeout(() => {
      this.menu.enable(true, 'portageMenu');
    }, 100);
    this.storage.get('userInfo', (val) => {
      console.log(val);
      if (val) {
        this.userInfo = val[0];
        this.utils.scrollContentFabControlDisplay(this.myElement, 'none');
        this.getSamplePortageList();
      }
    });
  }

  ionViewDidLoad() {
    this.globalVariables.notificationIsActive = true;
  }

  ionViewWillLeave() {
    this.menu.close('portageMenu');
    this.globalVariables.notificationIsActive = false;
  }


  loading: any;

  closePopup() {
    this.utils.loadingDismiss();
  }

  openDetails(ev: UIEvent, spList) {
    let popover = this.popoverCtrl.create(SamplePortagePopoverPage, {
      spList: spList
    });
    popover.present({
      ev: ev
    });
  }

  goCreateSamplePortage() {
    this.app.getRootNav().push(CreateSamplePortagePage);
  }

  //http://www.noiseaddicts.com/samples_1w72b820/3828.mp3


  doInfinite(infiniteScroll?: InfiniteScroll) {
    console.log('Begin async operation');

    setTimeout(() => {
      this.getSamplePortageList(infiniteScroll);
      console.log('Async operation has ended');

    }, 100);
  }

  openSideMenu(name) {
    this.menu.open(name);
  }

  closeSideMenu(name) {
    this.menu.close(name);
  }

  changeShorting(pipe, icon, side, color, pipeMesaj) {
    if (this.tempPipe !== pipe) {
      this.changePipe = pipe.replace("-", "");
      this.ascDesc = pipe[0] === "-" ? "desc" : "asc";
      this.shortIcon = icon;
      this.arrowSide = side;
      this.arrowSideColor = color;
      this.pipeMesaj = pipeMesaj;
      this.tempPipe = pipe;
      this.getSamplePortageList();
    }
  }

  getSamplePortageList(infiniteScroll?: InfiniteScroll, searchInput?: any) {
    this.searchInput = "";
    if (!infiniteScroll || infiniteScroll.state === "refreshing") {
      this.shouldEnableScrolling = true;
      this.limitToFirst = 0;
      this.top = 10;
      this.samplePortageList = [];
      this.utils.loadingPresent("Yükleniyor...");
    }//,SeciliDepartman
    if (searchInput) {
      this.shouldEnableScrolling = false;
      this.top = 100;
    }
    let expand = "?$expand=PorterKabul,PorterKabul/TeslimAlan,LaboratuvarKabul,IlgiliSLA,IlgiliSLA/ServisKategorisi,TeslimAlinanMahal,TeslimEdilenMahal";
    let filter = "";
    let seoUrl = "";
    let paging = "&$skip=" + this.limitToFirst + "&$top=" + this.top;
    let orderBy = "&$orderby=" + this.changePipe + " " + this.ascDesc;
    //this.changeShorting('Durum','hepsi-up.png',null,null);
    if (searchInput) {
      if (parseInt(searchInput))
        filter += "&$filter=IlgiliSLA/SCode eq " + searchInput;
      else
        filter += "&$filter=indexof(TeslimAlinanMahal/MahalKodu,'" + searchInput + "') gt -1" +
          " or indexof(TeslimAlinanMahal/MahalAdi,'" + searchInput + "') gt -1" +
          " or indexof(TeslimEdilenMahal/MahalKodu, '" + searchInput + "') gt - 1" +
          " or indexof(TeslimEdilenMahal/MahalAdi,'" + searchInput + "') gt -1" +
          " or indexof(IlgiliSLA/ServisKategorisi/KategoriAdi, '" + searchInput + "') gt - 1";
    }
    let select = "";

    seoUrl = "HelpDeskFMS_Module_NumuneTasima" + expand + filter + select + paging + orderBy + "&$inlinecount=allpages";
    this.serviceRequestProvider.getServiceRequest(seoUrl, null).subscribe(p => {
      this.utils.loadingDismiss();
      this.events.publish('portageCount', p["odata.count"]);
      if (p["value"].length > 0) {
        for (let i = 0; i < p["value"].length; i++) {
          this.utils.numuneKontrol(p["value"][i]);
          this.samplePortageList.push(p["value"][i]);
        }
        this.copy = this.samplePortageList;
        //this.serviceRequest = this.utils.sortList(this.serviceRequest,this.changePipe);
        this.limitToFirst += 10;
        if (p["value"].length < 10) {
          this.utils.toastMessage('Tüm Taşıma Talepleri Yüklendi...');
          this.shouldEnableScrolling = false;
        }
      }
      else {
        if (this.samplePortageList.length > 0) {
          this.utils.toastMessage('Tüm Taşıma Talepleri Yüklendi...');
          this.shouldEnableScrolling = false;
        }
        else {
          this.utils.toastMessage('Taşıma Talebi Yok...');
        }
      }
      if (this.limitToFirst >= 100) {
        this.utils.toastMessage('Tüm Taşıma Talepleri Yüklendi...');
        this.shouldEnableScrolling = false;
      }
      console.log(this.samplePortageList);
      if (infiniteScroll) {
        infiniteScroll.complete();
      }
      this.globalVariables.notificationIsActive = true;
    }, error => {
      this.utils.loadingDismiss();
      let me = this;
      // this.storage.get("serviceRequest").then(p => {
      //   this.serviceRequest = p;
      //   this.copy = p;
      //   this.utils.getDynamicValues(me.serviceRequest);
      // });
      this.globalVariables.notificationIsActive = true;
    });
  }

  scanBarcode(portage) {
    this.selectedPortage = portage;
    this.barcodeScanner.scan().then(barcodeData => {
      console.log('Barcode data', barcodeData);
      if (barcodeData.cancelled == true) {
        this.utils.loadingDismiss();
        return false;
      }
      else {
        let me = this;
        var barkod = barcodeData.text.replace('MECARD:N:,', '').replace(';ADR:;;', '');
        var varMi = portage.PorterKabul.find(element => { return element.BarkodNo === barkod });
        if (varMi) {
          this.utils.doConfirm("Numune Ekleme", "Bu Barkod daha önce eklenmiş. Numune Eklemeye devam edilsin mi ?", function () {
            me.scanBarcode(me.selectedPortage);
          }, function () {
            me.getSamplePortageList();
          })
        }
        else
          this.addSamplePortage(portage, barkod);
      }
    }).catch(err => {
      console.log('Error', err);
    });
  }

  addSamplePortage(portage, barkod) {
    let me = this;
    let seoUrl = "HelpDeskFMS_Module_NumuneTeslimAlma";
    let body = {
      "BarkodNo": barkod.toString(),
      "IlgiliTasima@odata.bind": this.apiUrl + "HelpDeskFMS_Module_NumuneTasima(guid'" + portage["Oid"] + "')",
      "TeslimAlan@odata.bind": this.apiUrl + "HelpDeskFMS_Module_Kullanici(guid'" + this.userInfo["Oid"] + "')"
    };
    this.utils.loadingPresent("Lütfen Bekleyiniz...");
    this.serviceRequestProvider.postServiceRequest(seoUrl, body).subscribe(res => {
      this.selectedPortage.PorterKabul.push(res);
      this.utils.loadingDismiss();
      this.utils.doConfirm("Numune Ekleme", "Numune Eklemeye devam edilsin mi ?", function () {
        me.scanBarcode(me.selectedPortage);
      }, function () {
        me.getSamplePortageList();
      })
    }, error => {
      this.utils.loadingDismiss();
      //me.utils.doAlert("Bağlantınızı kontrol ediniz...");
    });
  }

  filterItems(event: any, searchInput) {
    this.shouldEnableScrolling = event.target.value && searchInput !== '' ? false : true;
    this.samplePortageList = this.copy;
    this.samplePortageList = this.utils.filterItems(event, this.samplePortageList);
  }

  searchRequest(event: any, searchInput) {
    if (event.charCode === 13)
      this.getSamplePortageList(undefined, searchInput);
  }

  qrCodeGenerate(srCode) {
    this.utils.qrCodeGenerate(srCode);
  }

}



