import { Component, ViewChild } from '@angular/core';
import { IonicPage, NavController, NavParams, ViewController } from 'ionic-angular';
import { Slides } from 'ionic-angular';

import { DomSanitizer } from '@angular/platform-browser';

/**
 * Generated class for the ImageSliderPage page.
 *
 * See https://ionicframework.com/docs/components/#navigation for more info on
 * Ionic pages and navigation.
 */

@Component({
  selector: 'page-image-slider',
  templateUrl: 'image-slider.html',
})
export class ImageSliderPage {

  @ViewChild('mySlider') slides: Slides;

  base64Image:any;
  imageIndex:any;
  isSliding:boolean=true;

  constructor(public navCtrl: NavController,
              public navParams: NavParams, public viewCtrl:ViewController, public sanitizer:DomSanitizer) {
    this.base64Image=this.navParams.data.base64Image;
    this.imageIndex=this.navParams.data.imageIndex;

    let interval = setInterval(()=>{
      if(this.slides && this.slides.length() !==undefined) {
        this.slides.slideTo(this.imageIndex, 0,false);
        clearInterval(interval);
      }
    },100);
  }

  goToSlide(imageIndex) {
    if(this.isSliding){
      this.slides.slideTo(imageIndex+1,0,false);
      this.isSliding=false;
    }
  }

  ionViewDidLoad() {

  }

  closeModal() {
    this.viewCtrl.dismiss();
  }

}



