import { Component, Inject } from '@angular/core'
import { IonicPage, NavController, NavParams, ModalController } from 'ionic-angular'
import { StorageData } from '../../utils/storageData'
import { BarcodeScanner } from '@ionic-native/barcode-scanner'

import { Utils } from '../../utils/utils'
import { ServiceRequestProvider } from '../../providers/service-request/service-request'

import { LocaleListPage } from '../locale-list/locale-list'
import { ImageSliderPage } from '../image-slider/image-slider'

import { DomSanitizer } from '@angular/platform-browser'

/**
 * Generated class for the SlaRequestPage page.
 *
 * See https://ionicframework.com/docs/components/#navigation for more info on
 * Ionic pages and navigation.
 */

@Component({
	selector: 'page-sla-request',
	templateUrl: 'sla-request.html',
	providers: [Utils, ServiceRequestProvider, BarcodeScanner, StorageData]
})
export class SlaRequestPage {
	monthNames: string[] = ['Ocak', 'Şubat', 'Mart', 'Nisan', 'Mayıs', 'Haziran', 'Temmuz', 'Ağustos', 'Eylül', 'Ekim', 'Kasım', 'Aralık']
	monthShortNames: string[] = ['Oca', 'Şub', 'Mar', 'Nis', 'May', 'Haz', 'Tem', 'Ağu', 'Eyl', 'Eki', 'Kas', 'Ara']
	dayNames: string[] = ['Pazar', 'Pazartesi', 'Salı', 'Çarşamba', 'Perşembe', 'Cuma', 'Cumartesi']
	selectedLocale: any
	tarih: string = new Date().toISOString()
	saat: string = new Date(new Date().getTime() + 1000 * 60 * 60 * 3).toISOString()
	aciklama: any = ''
	userInfo: any = ''
	deviceInfo: any = ''
	base64Image: any[] = []
	base64PostImage: any[] = []
	base64Format: any = 'data:image/jpeg;base64,'

	constructor(public navCtrl: NavController, public navParams: NavParams, public storage: StorageData, public utils: Utils, public serviceRequestProvider: ServiceRequestProvider, public modalCtrl: ModalController, public barcodeScanner: BarcodeScanner, public sanitizer: DomSanitizer, @Inject('apiUrl') private apiUrl) {
		this.storage.get('deviceInfo', deviceInfo => {
			this.deviceInfo = '\n ( Cihaz Bilgi : ' + deviceInfo.mobilDeviceInfo + ' )'
		})
	}

	ionViewDidLoad() {
		console.log('ionViewDidLoad SlaRequestPage')
		//git push test
		// test ios
	}
	interval: any = ''
	ionViewWillEnter() {
		this.interval = setInterval(() => {
			this.tarih = new Date().toISOString()
			this.saat = new Date(new Date().getTime() + 1000 * 60 * 60 * 3).toISOString()
			//console.log(this.tarih + ' ' + this.saat)
		}, 1000)

		this.storage.get('userInfo', val => {
			this.userInfo = val[0]
		})
	}
	ionViewWillLeave() {
		clearInterval(this.interval)
	}
	isNumeric(str) {
		//if (typeof str != "string") return false;
		return !isNaN(str) && !isNaN(parseFloat(str))
	}
	myModal: any
	scanBarcode() {
		this.barcodeScanner
			.scan({ resultDisplayDuration: 0 })
			.then(barcodeData => {
				console.log('Barcode data', barcodeData)
				if (this.isNumeric(barcodeData.text.replace(/[^\d.-]+/g, ''))) {
					let seoUrl = "HelpDeskFMS_Module_Mahal?$filter=KareKod eq '" + barcodeData.text.replace(/[^\d.-]+/g, '') + "'&$format=json"
					this.serviceRequestProvider.getServiceRequest(seoUrl, null).subscribe(
						p => {
							if (barcodeData.cancelled == true) {
								this.utils.loadingDismiss()
								return false
							}
							this.utils.loadingDismiss()
							if (p['value'].length > 0) {
								this.selectedLocale = p['value'][0]
							} else {
								this.utils.toastMessage(barcodeData.text.replace(/[^\d.-]+/g, '') + ' barkodlu mahal Bulunamadı...')
								this.selectedLocale = null
							}
						},
						error => {
							this.utils.loadingDismiss()
						}
					)
				} else {
					barcodeData.text = barcodeData.text.replace('MECARD:N:,', '').replace(';ADR:;;', '')
					const mahalKodu = barcodeData.text.indexOf(' ') > -1 ? barcodeData.text.split(' ')[0] : barcodeData.text					
					let seoUrl = "HelpDeskFMS_Module_Mahal?$filter=MahalKodu eq '" + mahalKodu + "'&$format=json"
					let message = '<b>Aranan : ' + mahalKodu + '</b>' + '<br>' + 'Mahal Listesi Sorgulanıyor...'
					this.utils.loadingPresent(message)
					this.serviceRequestProvider.getServiceRequest(seoUrl, null).subscribe(
						p => {
							if (barcodeData.cancelled == true) {
								this.utils.loadingDismiss()
								return false
							}
							this.utils.loadingDismiss()
							if (p['value'].length > 0) {
								this.selectedLocale = p['value'][0]
							} else {
								this.utils.toastMessage('Mahal Bulunamadı...')
								this.selectedLocale = null
							}
						},
						error => {
							this.utils.loadingDismiss()
						}
					)
				}
			})
			.catch(err => {
				console.log('Error', err)
			})
	}
	clearLocale() {
		let me = this
		this.utils.doConfirm('Mahal Seçimi', 'Seçimi kaldırmak istediğinizden emin misiniz ?', function () {
			me.selectedLocale = null
		})
	}
	selectLocale() {
		this.myModal = this.modalCtrl.create(LocaleListPage, {})
		this.myModal.onDidDismiss(data => {
			if (data) this.selectedLocale = data
		})
		this.myModal.present()
	}

	slaTalebi() {
		let me = this
		let seoUrl = 'HelpDeskFMS_Module_BackOfficeMaster'
		let body = {
			'odata.type': 'XafDataService.HelpDeskFMS_Module_WebSLA',
			'TalepEden@odata.bind': this.apiUrl + "HelpDeskFMS_Module_Kullanici(guid'" + this.userInfo['Oid'] + "')",
			Aciklama: this.aciklama,
			SlaOlustumu: false,
			Tarih: this.tarih.substring(0, 11) + this.saat.substring(11)
		}
		if (this.selectedLocale) {
			body['IlgiliMahal@odata.bind'] = this.apiUrl + "HelpDeskFMS_Module_Mahal(guid'" + this.selectedLocale['Oid'] + "')"
		}
		if(this.aciklama && this.aciklama.length > 0 && this.selectedLocale) {
			let message = 'SLA Talebi oluşturulsun mu ?'
			this.utils.doConfirm('SLA Talebi', message, function () {
				me.utils.loadingPresent('Lütfen Bekleyiniz...')
				me.serviceRequestProvider.postServiceRequest(seoUrl, body).subscribe(
					p => {
						const oid = p['oid']
						me.utils.loadingDismiss()
						me.utils.doAlertConfirm('İşlem başarılı...', function () {
							me.selectedLocale = null
							me.aciklama = ''
							if (me.base64PostImage.length > 0) {
								me.utils.loadingPresent('Fotoğraflar Aktarılıyor...')
								let i = 0
								while (i < me.base64PostImage.length) {
									let body = {
										'IlgiliServisIstegi@odata.bind': me.apiUrl + "HelpDeskFMS_Module_ServisIstegi(guid'" + oid + "')",
										B64: me.base64PostImage[i].replace(me.base64Format, '')
									}
									me.serviceRequestProvider.sendPhotos(body, true).subscribe(
										p => {
										},
										error => {
											me.utils.loadingDismiss()
											console.log(error)
										}
									)
									if (i == (me.base64PostImage.length - 1)) {
										me.utils.loadingDismiss()
										me.navCtrl.pop()
										me.utils.processOK()
									}
									i++
								}
							} else {
								me.navCtrl.pop()
								me.utils.processOK()
							}
						})
					},
					error => {
						me.utils.loadingDismiss()
						//me.utils.doAlert("Bağlantınızı kontrol ediniz...");
					}
				)
			})			
		} else {
			this.utils.doAlert('SLA oluşturmak için bir mahal seçmeli ve açıklama alanını doldurmalısınız!')
		}
	}
	openCamera() {
		let me = this
		this.utils.openCamera(function (imageData) {
			me.base64Image.push(me.base64Format + imageData)
			me.base64PostImage.push(me.base64Format + imageData)
		})
	}
	imageSlider(imageIndex) {
		let myModal = this.modalCtrl.create(ImageSliderPage, {
			base64Image: this.base64PostImage,
			imageIndex: imageIndex
		})
		myModal.present()
	}
	removeImage(imageIndex) {
		let me = this
		this.utils.doConfirm('Fotoğraf Sil', 'Fotoğrafı silmek istediğinizden emin misiniz ?', function () {
			me.utils.removeImage(me.base64Image, imageIndex)
			me.utils.removeImage(me.base64PostImage, imageIndex)
		})
	}
}



