import { StateEnums } from './../../enums/state-enums';
import { Component, ViewChild, ElementRef, Inject } from '@angular/core';
import { IonicPage, NavController, ViewController, MenuController, NavParams, App, Scroll, Slides, Content } from 'ionic-angular';

import { Utils } from '../../utils/utils';
import { StorageData } from '../../utils/storageData';

import { ServiceRequestPage } from '../service-request/service-request'
import { ServiceRequestProvider } from '../../providers/service-request/service-request';

/**
 * Generated class for the AssigningPersonPage page.
 *
 * See https://ionicframework.com/docs/components/#navigation for more info on
 * Ionic pages and navigation.
 */

@Component({
  selector: 'page-assigning-person',
  templateUrl: 'assigning-person.html',
  providers: [Utils, ServiceRequestProvider, StorageData]
})
export class AssigningPersonPage {

  @ViewChild(Slides) slides: Slides;
  @ViewChild('segmentScroll') segmentScroll: Scroll;
  @ViewChild('scrollContent') content: Content;
  @ViewChild('scrollFabButton') myElement: ElementRef;

  stateEnums: any;

  personalList: any;
  copy: any;
  aciklama: any = "";
  sr: any;
  searchUser: any;
  slideIndex: any = 0;
  changePipe: string = "adi";
  selectedPerson: any = null;
  title: string = "Birim Personelleri";
  deviceInfo: any = "";


  constructor(public navCtrl: NavController,
    public viewCtrl: ViewController, public menu: MenuController,
    public navParams: NavParams, public app: App, public utils: Utils,
    public serviceRequestProvider: ServiceRequestProvider, public storage: StorageData, @Inject('apiUrl') private apiUrl) {
    this.personalList = navParams.data.personalList.value;
    this.copy = this.personalList;
    this.sr = navParams.data.sr;
    this.stateEnums = StateEnums;
    console.log(this.personalList);
    this.storage.get("deviceInfo", (deviceInfo) => {
      this.deviceInfo = "\n ( Cihaz Bilgi : " + deviceInfo.mobilDeviceInfo + " )";
      console.log("");
    });

  }

  setSegmentScroll(selectedPipe) {
    if (selectedPipe == "adi" || selectedPipe == "-adi" || selectedPipe == "isOnline") {
      this.segmentScroll["_scrollContent"].nativeElement.scrollLeft = 0;
    }
    else {
      this.segmentScroll["_scrollContent"].nativeElement.scrollLeft = 75;
    }
  }
  ngAfterViewInit() {
    this.utils.scrollContentFabControl(this.content, this.myElement);
    this.slides.lockSwipes(true);
  }

  ionViewWillEnter() {
    this.utils.scrollContentFabControlDisplay(this.myElement, 'none');
  }

  scrollTop(duration) {
    this.content.scrollToTop(duration);
  }

  ionViewDidLoad() {
    console.log('ionViewDidLoad AssigningPersonPage');
  }

  dismiss() {
    this.viewCtrl.dismiss();
  }
  slideChange(slideIndex) {
    this.title = "Birim Personelleri";
    this.slideIndex = slideIndex;
    if (slideIndex == 0) {
      this.slides["_elementRef"].nativeElement.firstElementChild.style.height = 'auto';
    }
    if (slideIndex == 1) {
      this.utils.scrollContentFabControlDisplay(this.myElement, 'none');
    }
    this.slides.lockSwipes(false);
    this.slides.slideTo(this.slideIndex, 500);
    this.slides.lockSwipes(true);
  }
  selectedPersonal(selectedPerson, slideIndex) {
    this.slides["_elementRef"].nativeElement.firstElementChild.style.height = '165px';
    this.scrollTop(0);
    this.title = "Kişiye Atama";
    this.slideIndex = slideIndex;
    this.selectedPerson = selectedPerson;
    this.slides.lockSwipes(false);
    this.slides.slideTo(this.slideIndex, 500);
    this.slides.lockSwipes(true);
  }

  filterItems(event: any) {
    this.personalList = this.copy;
    this.personalList = this.utils.filterItems(event, this.personalList);
  }

  assigningPerson() {
    let me = this;
    let select = "?$select=Durum";
    let seoUrl = "HelpDeskFMS_Module_ServisIstegi(guid'" + this.sr["Oid"] + "')" + select;
    this.utils.loadingPresent("Servis isteğinin son durumu kontrol ediliyor..");
    me.serviceRequestProvider.getServiceRequest(seoUrl, null).subscribe(res => {
      this.utils.loadingDismiss();
      let durum = res["Durum"];
      if (durum === 20 || durum === 30 || durum === 40 || durum === 62 || durum === 82) {
        seoUrl = "HelpDeskFMS_Module_Islem";
        let body = {
          "odata.type": "XafDataService.HelpDeskFMS_Module_SE_Kisiyeata",
          "IlgiliServisIstegi@odata.bind": this.apiUrl + "HelpDeskFMS_Module_ServisIstegi(guid'" + this.sr["Oid"] + "')",
          "AtananKullanici@odata.bind": this.apiUrl + "HelpDeskFMS_Module_Kullanici(guid'" + this.selectedPerson["Oid"] + "')",
          "Aciklama": this.aciklama
        };
        let message = "Servis isteği " + '<b>' + this.selectedPerson["adi"] + "  " + this.selectedPerson["soyadi"] + '</b>' + " isimli personele atansın mı ?";
        this.utils.doConfirm("Kişiye Ata", message, function () {
          me.utils.loadingPresent("Lütfen Bekleyiniz...");
          me.serviceRequestProvider.postServiceRequest(seoUrl, body).subscribe(p => {
            me.utils.loadingDismiss();
            me.utils.doAlertConfirm("İşlem başarılı...", function () {
              me.viewCtrl.dismiss();
              me.utils.processOK();
              let seoUrl = "PushGonder?Oid=guid'" + me.selectedPerson["Oid"] + "'&Baslik='👨🏻‍🔧 Servis İsteği'&Mesaj='" + me.sr.konu.Olay + "'";
              me.serviceRequestProvider.getServiceRequest(seoUrl, null).subscribe(res => {
                console.log(res);
              });
            });
          }, error => {
            me.utils.loadingDismiss();
          });
        })
      }
      else {
        let message = "Son Durumu <b>'" + this.stateEnums["state" + durum] + "'</b> olan servis isteği üzerinde '<b>Kişiye Atama</b>' işlemi yapamazsınız!'"
        this.utils.doAlert(message);
      }
    }, error => {
      me.utils.loadingDismiss();
    });
  }

}



