import { SlaListPage } from './../sla-list/sla-list';
import { MonthNames, MonthShortNames, DayNames } from './../../lists/dates';
import { Component, Inject } from '@angular/core';
import { IonicPage, NavController, NavParams, ModalController } from 'ionic-angular';
import { LocaleListPage } from '../locale-list/locale-list';
import { ServiceRequestProvider } from '../../providers/service-request/service-request';
import { Utils } from '../../utils/utils';

/**
 * Generated class for the CreateSamplePortagePage page.
 *
 * See https://ionicframework.com/docs/components/#navigation for more info on
 * Ionic pages and navigation.
 */

@Component({
  selector: 'page-create-sample-portage',
  templateUrl: 'create-sample-portage.html',
  providers: [Utils, ServiceRequestProvider]
})
export class CreateSamplePortagePage {

  monthNames: string[] = MonthNames;
  monthShortNames: string[] = MonthShortNames;
  dayNames: string[] = DayNames;
  tarih: string = new Date().toISOString();
  saat: string = new Date(new Date().getTime() + 1000 * 60 * 60 * 3).toISOString();
  selectedSla:any=null;
  selectedLocale1:any=null;
  selectedLocale2:any=null;

  constructor(public navCtrl: NavController, public modalCtrl: ModalController, public utils: Utils, public navParams: NavParams,
    public serviceRequestProvider: ServiceRequestProvider,@Inject('apiUrl') private apiUrl) {
  }

  ionViewDidLoad() {
    console.log('ionViewDidLoad CreateSamplePortagePage');
  }

  localeModal:any;
  selectLocale(selectedLocal) {
    this.localeModal = this.modalCtrl.create(LocaleListPage, {

    });
    this.localeModal.onDidDismiss((data) => {
      if (data)
        this[selectedLocal] = data;
    });
    this.localeModal.present();
  }

  slaModal:any;
  selectSla() {
    this.slaModal = this.modalCtrl.create(SlaListPage, {

    });
    this.slaModal.onDidDismiss((data) => {
      if (data)
        this.selectedSla = data;
    });
    this.slaModal.present();
  }

  createSamplePortage() {
    let me = this;
    let seoUrl = "HelpDeskFMS_Module_NumuneTasima";
    let body:any = {
      "Tarih": this.tarih.substring(0, 11) + this.saat.substring(11)
    };
    //"HelpDeskFMS_Module_NumuneTasima(guid'" + portage["Oid"] + "')"
    if(this.selectedSla)
      body["IlgiliSLA@odata.bind"] = this.apiUrl + "HelpDeskFMS_Module_ServisIstegi(guid'" + this.selectedSla["Oid"] + "')";
    if (this.selectedLocale1)
      body["TeslimAlinanMahal@odata.bind"] = this.apiUrl + "HelpDeskFMS_Module_Mahal(guid'" + this.selectedLocale1["Oid"] + "')";
    if (this.selectedLocale2)
      body["TeslimEdilenMahal@odata.bind"] = this.apiUrl + "HelpDeskFMS_Module_Mahal(guid'" + this.selectedLocale2["Oid"] + "')";
    this.utils.doConfirm("Numune Taşıma", "Numune Taşıma oluşturulsun mu ?", function () {
      me.utils.loadingPresent("Lütfen Bekleyiniz...");
      me.serviceRequestProvider.postServiceRequest(seoUrl, body).subscribe(p => {
        me.utils.loadingDismiss();
        me.navCtrl.pop();
        me.utils.processOK();
      }, error => {
          me.utils.loadingDismiss();
        //me.utils.doAlert("Bağlantınızı kontrol ediniz...");
      });
    })
  }

}



