import { StateEnums } from './../../enums/state-enums';
import { Component, Inject } from '@angular/core';
import { IonicPage, NavController, ModalController, NavParams, Platform } from 'ionic-angular';

import { Base64 } from '@ionic-native/base64';
import { DomSanitizer } from '@angular/platform-browser';
import { StorageData } from '../../utils/storageData';

import { Utils } from '../../utils/utils';
import { ServiceRequestProvider } from '../../providers/service-request/service-request';

import { ImageSliderPage } from '../image-slider/image-slider'

import { ApprovalRuleList } from '../../lists/approval-rule-list'
import { MonthNames, MonthShortNames, DayNames } from '../../lists/dates';

/**
 * Generated class for the ExtendingSlaPage page.
 *
 * See https://ionicframework.com/docs/components/#navigation for more info on
 * Ionic pages and navigation.
 */

@Component({
  selector: 'page-extending-sla',
  templateUrl: 'extending-sla.html',
  providers: [Base64, Utils, ServiceRequestProvider, StorageData]
})
export class ExtendingSlaPage {

  stateEnums: any;

  monthNames: string[] = MonthNames;
  monthShortNames: string[] = MonthShortNames;
  dayNames: string[] = DayNames;
  approvalRuleList: any;
  selectedApprovalRule: any = 0;
  teslimTarihi: string = new Date().toISOString();
  teslimSaati: string = new Date(new Date().getTime() + 1000 * 60 * 60 * 3).toISOString();
  sr: any;
  aciklama: any = "";
  base64Image: any[] = [];
  //base64PostImage:any[]=["assets/imgs/service.png","assets/imgs/service2.png","assets/imgs/service.png","assets/imgs/service.png","assets/imgs/service2.png"];
  base64PostImage: any[] = [];
  deviceInfo: any = "";
  userInfo: any = "";
  base64Format: any = "data:image/jpeg;base64,";

  constructor(public navCtrl: NavController,
    public modalCtrl: ModalController,
    public navParams: NavParams, public utils: Utils,
    public base64: Base64, public platform: Platform,
    public serviceRequestProvider: ServiceRequestProvider, public sanitizer: DomSanitizer, public storage: StorageData, @Inject('apiUrl') private apiUrl) {
    this.approvalRuleList = ApprovalRuleList;
    this.sr = navParams.data.sr;
    this.stateEnums = StateEnums;
    this.storage.get("deviceInfo", (deviceInfo) => {
      this.deviceInfo = "\n ( Cihaz Bilgi : " + deviceInfo.mobilDeviceInfo + " )";

    });
  }

  openCamera() {
    let me = this;
    this.utils.openCamera(function (imageData) {
      me.base64Image.push(me.base64Format + imageData);
      me.base64PostImage.push(me.base64Format + imageData);
    });
  }

  imageSlider(imageIndex) {
    let myModal = this.modalCtrl.create(ImageSliderPage, {
      base64Image: this.base64PostImage,
      imageIndex: imageIndex
    });
    myModal.present();
  }

  removeImage(imageIndex) {
    let me = this;
    this.utils.doConfirm("Fotoğraf Sil", "Fotoğrafı silmek istediğinizden emin misiniz ?", function () {
      me.utils.removeImage(me.base64Image, imageIndex);
      me.utils.removeImage(me.base64PostImage, imageIndex);
    });
  }

  ionViewDidLoad() {
    console.log('ionViewDidLoad ExtendingSlaPage');
  }
  ionViewWillEnter() {
    this.storage.get('userInfo', (val) => {
      this.userInfo = val[0];
    });
  }

  extendingSLA() {
    let me = this;
    let select = "?$select=Durum";
    let seoUrl = "HelpDeskFMS_Module_ServisIstegi(guid'" + this.sr["Oid"] + "')" + select;
    this.utils.loadingPresent("Servis isteğinin son durumu kontrol ediliyor..");
    me.serviceRequestProvider.getServiceRequest(seoUrl, null).subscribe(res => {
      this.utils.loadingDismiss();
      let durum = res["Durum"];
      if (durum === 30 || durum === 40 || durum === 42 || durum === 62 || durum === 70 || durum === 72) {
        seoUrl = "HelpDeskFMS_Module_Islem";
        let body = {
          "odata.type": "XafDataService.HelpDeskFMS_Module_SE_SLAUzat",
          "IlgiliServisIstegi@odata.bind": this.apiUrl + "HelpDeskFMS_Module_ServisIstegi(guid'" + this.sr["Oid"] + "')",
          "Aciklama": this.aciklama,
          "TahminiTamamlanmaTarihi": this.teslimTarihi.substring(0, 11) + this.teslimSaati.substring(11).replace('Z', '')
        };
        let goalTime = new Date(this.sr["Goal2"]);
        let slaTime = new Date(new Date(this.teslimTarihi.substring(0, 11) + this.teslimSaati.substring(11)).getTime() - 1000 * 60 * 60 * 2);
        if (slaTime > goalTime) {
          let message = "SLA Uzatma isteği gönderilsin mi ?";
          this.utils.doConfirm("SLA Uzatma", message, function () {
            me.utils.loadingPresent("Lütfen Bekleyiniz...");
            me.serviceRequestProvider.postServiceRequest(seoUrl, body).subscribe(p => {
              me.utils.loadingDismiss();
              me.utils.doAlertConfirm("İşlem başarılı...", function () {
                if (me.base64PostImage.length > 0) {
                  me.utils.loadingPresent("Fotoğraflar Aktarılıyor...");
                  let i = 0;
                  while (i < me.base64PostImage.length) {
                    let body = {
                      "IlgiliServisIstegi@odata.bind": me.apiUrl + "HelpDeskFMS_Module_ServisIstegi(guid'" + me.sr["Oid"] + "')",
                      "B64": me.base64PostImage[i].replace(me.base64Format, '')
                    };
                    me.serviceRequestProvider.sendPhotos(body).subscribe(p => {
                      if (i == (me.base64PostImage.length - 1)) {
                        me.utils.loadingDismiss();
                        me.navCtrl.pop();
                        me.utils.processOK();
                      }
                    }, error => {
                      me.utils.loadingDismiss();
                      console.log(error);
                    });
                    i++;
                  }
                }
                else {
                  me.navCtrl.pop();
                  me.utils.processOK();
                }
              });
            }, error => {
              me.utils.loadingDismiss();
            });
          })
        }
        else {
          me.utils.doAlert("Sla Uzatma Tarihi <br><b>" +
            this.sr["Goal2"].replace('T', ' ').substring(0, this.sr["Goal2"].indexOf('.')) +
            "</b> Tarihinden Büyük Olmalıdır...");
        }
      }
      else {
        let message = "Son Durumu <b>'" + this.stateEnums["state" + durum] + "'</b> olan servis isteği üzerinde '<b>Sla Uzatma</b>' işlemi yapamazsınız!'"
        this.utils.doAlert(message);
      }
    }, error => {
      me.utils.loadingDismiss();
    });
  }

}



