import { NgModule } from '@angular/core';
import { OrderByPipe } from './order-by/order-by';
import { BadgeFilterPipe } from './badge-filter/badge-filter';
import { DatePipe } from './date/date';
import { PercentPipe } from './percent/percent';
@NgModule({
	declarations: [
    OrderByPipe,
    BadgeFilterPipe,
    DatePipe,
    PercentPipe],
	imports: [],
	exports: [
    OrderByPipe,
    BadgeFilterPipe,
    DatePipe,
    PercentPipe]
})
export class PipesModule {
  static forRoot() {
    return {
      ngModule: PipesModule,
      providers: [],
    };
  }
}



