import { Component, Inject, ViewChild } from '@angular/core'
import { App, Events, FabContainer, ModalController, NavController, NavParams, Slides, ViewController } from 'ionic-angular'

import { GlobalVariables } from '../../globalVariables/global-variables'
import { ServiceRequestProvider } from '../../providers/service-request/service-request'
import { Utils } from '../../utils/utils'

import { StateEnums } from '../../enums/state-enums'
import { TypeEnums } from '../../enums/type-enums'

import { HydpEnums } from '../../enums/hydp-enums'
import { Addition22Page } from '../addition22/addition22'
import { AssigningPersonPage } from '../assigning-person/assigning-person'
import { ExtendingSlaPage } from '../extending-sla/extending-sla'
