import { Injectable, Inject } from '@angular/core';
import { Http, Headers, Response, RequestOptions } from '@angular/http';
import { HttpClient } from '@angular/common/http';

import { Observable } from 'rxjs/Observable';
import 'rxjs/add/operator/map';
import 'rxjs/add/operator/do';
import 'rxjs/add/operator/catch';
import { map } from 'rxjs/operators';

/*
 Generated class for the ServiceRequestProvider provider.

 See https://angular.io/guide/dependency-injection for more info on providers
 and Angular DI.
 */
@Injectable()
export class ServiceRequestProvider {

  headers;
  options;

  constructor(public http: HttpClient, @Inject('apiUrl') private apiUrl, @Inject('apiUrlGoogleTest') private apiUrlGoogleTest) {

  }

  setHeader(header) {
    this.headers = "";
    this.options = "";
    this.headers = new Headers();
    this.headers.set('Content-Type', 'application/json');
    this.headers.set('Accept', 'application/json');
    if (header) {
      this.headers.set("Authorization", "Basic " + btoa(header["user"] + ":" + header["pass"]));
    }
    else {
      this.headers.set("Authorization", "Basic " + btoa("mymadmin" + ":" + "nanoturk"));
    }
    this.options = new RequestOptions({ headers: this.headers, withCredentials: false });
  }
  login(seoUrl) {
    let response = this.http.get(this.apiUrl + seoUrl);
    return response;
  }

  getServiceRequest(seoUrl, header) {
    let response = this.http.get(this.apiUrl + seoUrl);
    return response;
  }

  postServiceRequest(seoUrl, body) {
    let response = this.http.post(this.apiUrl + seoUrl, body);
    return response;
    //.map(response =>response.json());
  }

  putServiceRequest(seoUrl, body) {
    let response = this.http.patch(this.apiUrl + seoUrl, body);
    return response;
    //.map(response =>response.json());
  }

  sendPhotos(body, file = false) {
    let seoUrl = file ? "HelpDeskFMS_Module_SLADosyaEk" : "HelpDeskFMS_Module_SLAEk";
    let response = this.http.post(this.apiUrl + seoUrl, body);
    return response;
    //.map(response =>response.json());
  }

  postServiceGoogleTest(body) {
    let response = this.http.post(this.apiUrlGoogleTest, body);
    return response;
    //.map(response =>response.json());
  }

  getMockList(param: any): Observable<any[]> {
    const msgListUrl = `../assets/mock/${param}.json`;
    return this.http.get<any>(msgListUrl)
      .pipe(map(response => response));
  }
}



