import { SamplePortagePage } from './../sample-portage/sample-portage';
import { Component, ViewChild } from '@angular/core';
import { Platform, Events, Tabs } from 'ionic-angular';

import { ServiceRequestPage } from '../service-request/service-request';
import { SlaRequestPage } from "../sla-request/sla-request";
import { SettingsPage } from "../settings/settings";
import { Utils } from '../../utils/utils';
import { ChatService } from "../../providers/chat-service";
import { StorageData } from '../../utils/storageData';
import { USER } from '../../globalVariables/global-variables';

@Component({
  templateUrl: 'tabs.html',
  providers: [ChatService, Utils, StorageData]
})
export class TabsPage {

  @ViewChild('myTabs') myTabs: Tabs;

  tab1Root = ServiceRequestPage;
  tab2Root = SamplePortagePage;
  tab3Root = SlaRequestPage;
  tab4Root = SettingsPage;
  serviceBadgeCount: number;
  portageBadgeCount: number;
  userInfo: any = "";

  constructor(public chatService: ChatService,
    public utils: Utils, public platform: Platform, public storage: StorageData, public events: Events) {
    this.platform.registerBackButtonAction(() => {

    });
    this.events.subscribe('serviceCount', (data) => {
      this.serviceBadgeCount = data;
    });
    this.events.subscribe('portageCount', (data) => {
      this.portageBadgeCount = data;
    });
    /*this.broadcaster.addEventListener('serviceCount').subscribe((event) =>
      this.badgeCount=event.serviceCount
    );*/
    /*platform.registerBackButtonAction(() =>
    {
      this.utils.doConfirm("Uygulamadan Çık","Çıkmak istediğinizden emin misiniz ?",function () {
        platform.exitApp();
      });
    });*/
  }
  clickTab() {
    console.log(this.myTabs);
    /*this.events.publish('scrollToTop');*/
  }
  ionViewDidLoad() {
    console.log('ionViewDidLoad SecondPage');
  }
  ionViewWillEnter() {
    this.userInfo = USER.userInfo;
  }
}

