import { Component } from '@angular/core';
import { IonicPage, NavController, NavParams, App } from 'ionic-angular';

import { StorageData } from '../../utils/storageData';

import { ServiceRequestProvider } from '../../providers/service-request/service-request';
import { Utils } from '../../utils/utils';

import { LoginPage } from '../../pages/login/login';

/**
 * Generated class for the SettingsPage page.
 *
 * See https://ionicframework.com/docs/components/#navigation for more info on
 * Ionic pages and navigation.
 */

@Component({
  selector: 'page-settings',
  templateUrl: 'settings.html',
  providers: [ServiceRequestProvider, Utils, StorageData]
})
export class SettingsPage {

  constructor(public navCtrl: NavController,
    public navParams: NavParams, public app: App,
    public storage: StorageData,
    public serviceRequestProvider: ServiceRequestProvider,
    public utils: Utils) {
  }

  ionViewDidLoad() {
    console.log('ionViewDidLoad SettingsPage');
  }

  goPage() {
    this.utils.loadingPresent("Çıkış Yapılıyor...");
    this.storage.get("userInfo", (userInfo) => {
      let seourl = "HelpDeskFMS_Module_Kullanici" + "(guid'" + userInfo[0]["Oid"] + "')";
      let body = {
        "MobilUUID": null,
        "OturumAcilanCihaz": null
      };
      this.serviceRequestProvider.putServiceRequest(seourl, body).subscribe(p => {
        this.utils.loadingDismiss();
        this.storage.remove("userInfo");
        this.storage.remove('my_token');
        this.storage.clear();
        window.localStorage.clear();
        this.app.getRootNav().setRoot(LoginPage);
      }, error => {
        this.utils.loadingDismiss();
        /*this.utils.doAlert("Bağlantınızı kontrol ediniz...");*/
        /*this.file.listDir(this.file.cacheDirectory,'').then((result)=>{
          for(let file of result){
            this.file.removeFile(this.file.cacheDirectory, file.name) ;
            this.file.removeRecursively(this.file.cacheDirectory, file.name).catch(err => {});
          }
        }) ;*/
        this.storage.remove("userInfo");
        this.storage.remove('my_token');
        this.app.getRootNav().setRoot(LoginPage);
      });
    });
  }
}



