import { StateEnums } from './../../enums/state-enums'
import { Component, ViewChild, ElementRef } from '@angular/core'
import { IonicPage, NavController, NavParams, Content, ViewController, InfiniteScroll } from 'ionic-angular'
import { ServiceRequestProvider } from '../../providers/service-request/service-request'
import { Utils } from '../../utils/utils'

/**
 * Generated class for the SlaListPage page.
 *
 * See https://ionicframework.com/docs/components/#navigation for more info on
 * Ionic pages and navigation.
 */

@Component({
	selector: 'page-sla-list',
	templateUrl: 'sla-list.html',
	providers: [ServiceRequestProvider, Utils]
})
export class SlaListPage {
	@ViewChild('scrollContent') content: Content
	@ViewChild('scrollFabButton') myElement: ElementRef

	slaList: any[] = []
	copy: any[] = []
	searchSla: any
	stateEnums: any
	shouldEnableScrolling: boolean = false
	limitToFirst: number = 0
	top: number = 20

	constructor(public navCtrl: NavController, public navParams: NavParams, public viewCtrl: ViewController, public serviceRequestProvider: ServiceRequestProvider, public utils: Utils) {
		this.stateEnums = StateEnums
	}

	ionViewDidLoad() {
		console.log('ionViewDidLoad LocaleListPage')
	}

	ionViewWillEnter() {
		this.utils.scrollContentFabControlDisplay(this.myElement, 'none')
		this.getSlaList(null)
	}

	ngAfterViewInit() {
		this.utils.scrollContentFabControl(this.content, this.myElement)
	}

	scrollTop() {
		this.content.scrollToTop(250)
	}

	dismiss(selectedLocale) {
		this.viewCtrl.dismiss(selectedLocale)
	}

	filterItems(event: any) {
		this.slaList = this.copy
		this.slaList = this.utils.filterItems(event, this.slaList)
	}

	doInfinite(infiniteScroll?: InfiniteScroll) {
		console.log('Begin async operation')

		setTimeout(() => {
			this.getSlaList(infiniteScroll)
			console.log('Async operation has ended')
		}, 100)
	}

	getSlaList(infiniteScroll?: InfiniteScroll, searchInput?: any) {
		if (!infiniteScroll || infiniteScroll.state === 'refreshing') {
			this.slaList = []
			this.shouldEnableScrolling = true
			this.limitToFirst = 0
			this.top = 20
		}
		if (this.searchSla != '') {
			searchInput = this.searchSla
		}
		if (searchInput) {
			this.slaList = []
			this.limitToFirst = 0
			this.top = 100
		}
		let expand = '?$expand=ServisKategorisi,ilgiliMahal'
		let filter = '&$filter=IlgiliServis ne null '
		let paging = '&$skip=' + this.limitToFirst + '&$top=' + this.top + '&$orderby=SCode desc'
		let message = 'Sla Aranıyor...'
		//this.changeShorting('Durum','hepsi-up.png',null,null);
		if (searchInput) {
			message = '<b>Aranan : ' + searchInput + '</b>' + '<br>' + 'Sla Aranıyor...'
			if (parseInt(searchInput)) filter += 'and SCode eq ' + searchInput + ' '
			else filter += "and (indexof(ilgiliMahal/MahalKodu,'" + searchInput + "') gt -1" + " or indexof(ilgiliMahal/MahalAdi,'" + searchInput + "') gt -1" + " or indexof(ServisKategorisi/KategoriAdi, '" + searchInput + "') gt -1) "
		}
		let seoUrl = 'HelpDeskFMS_Module_ServisIstegi' + expand + filter + paging
		this.utils.loadingPresent(message)
		this.serviceRequestProvider.getServiceRequest(seoUrl, null).subscribe(
			p => {
				if (p['value'].length > 0) {
					this.slaList.push(...p['value'])
					this.copy = this.slaList
					//this.searchSla = ''
				}
				console.log(this.slaList)
				this.utils.loadingDismiss()
				if (infiniteScroll) {
					infiniteScroll.complete()
				}
			},
			error => {
				this.utils.loadingDismiss()
			}
		)
	}
}



