import { Component } from '@angular/core';
import { Platform, App, ToastController } from 'ionic-angular';
import { StatusBar } from '@ionic-native/status-bar';
import { SplashScreen } from '@ionic-native/splash-screen';
import { FCM } from 'cordova-plugin-fcm-with-dependecy-updated/ionic/ngx';
import { AppVersion } from '@ionic-native/app-version';

import { LoginPage } from '../pages/login/login';

import { ChatService } from "../providers/chat-service";

import { Utils } from '../utils/utils'
import { StorageData } from '../utils/storageData';
import { TabsPage } from '../pages/tabs/tabs';
import { USER } from '../globalVariables/global-variables';




@Component({
  templateUrl: 'app.html',
  providers: [Utils, ChatService, StorageData]
})
export class MyApp {
  rootPage: any;

  constructor(platform: Platform, statusBar: StatusBar, splashScreen: SplashScreen, appVersion: AppVersion,
    app: App, utils: Utils, firebase: FCM, toastCtrl: ToastController, storage: StorageData, chatService: ChatService) {
    platform.ready().then(() => {
      this.rootPage = LoginPage;
      if (storage.get('userInfo')) {
        USER.userInfo = storage.get('userInfo')[0];
        this.rootPage = TabsPage;
      }
      appVersion.getVersionNumber().then((res) => {
        console.log(res);
        //localStorage.setItem("app_v", res);
      }, (err) => {
        console.log(err);
      });
      // Okay, so the platform is ready and our plugins are available.
      // Here you can do any higher level native things you might need.
      statusBar.styleDefault();
      //statusBar.overlaysWebView(true);
      statusBar.backgroundColorByHexString('#009688');//008275
      splashScreen.hide();
      /*platform.registerBackButtonAction(() =>
      {
        utils.doConfirm("Uygulamadan Çık","Çıkmak istediğinizden emin misiniz ?",function () {
          platform.exitApp();
        })
      });*/

      /*firebase.getToken().then(token =>
        storage.set("token",token))
        .catch(err=> console.log(err));*/

        firebase.onNotification().subscribe(data => {
          if (data.wasTapped) {
            console.log("Received in background");
          } else {
            console.log("Received in foreground");
          };
        });

      if (platform.is('android')) {
        firebase.getToken().then(token =>
          {
            storage.set("token", token)
            console.log(token)
          })
          .catch(err => console.log(err));
      }

      if (platform.is('ios')) {
        firebase.requestPushPermission().then(r => console.log('permission : ' + r)).catch(e => console.log('permission : ' + e))
        firebase.getToken().then(token =>
          {
            storage.set("token", token)
            console.log(token)
          })
          .catch(err => console.log(err));
      }

    });

    // chatService.getMsgList().subscribe(res => {
    //  /* broadcaster.fireNativeEvent('chatMsg',{
    //     msgListCount:res.length
    //   }).then(() => console.log('success'));*/
    //     });

  }
}



