  RenkGetir(val) {
    val = (val > 1) ? 1 : val;
    val = (val < 0) ? 0 : val;
    let veri = this.GetColor(val);
    return "rgba(" + veri.R.toString() + "," + veri.G.toString() + "," + veri.B.toString() + ",1)"
  }
  GetColor(num) {
    let High = { A: 1, R: 248, G: 105, B: 107 };
    let Mid = { A: 1, R: 255, G: 235, B: 132 };
    let Low = { A: 1, R: 99, G: 190, B: 123 };
    let minimumValue = 0;
    let maximumValue = 1;
    let lowColor = Low;
    let middleColor = Mid;
    let highColor = High;
    let num2 = (minimumValue + maximumValue) / 2;
    if (num < num2) {
      highColor = middleColor;
      maximumValue = num2;
    }
    else {
      lowColor = middleColor;
      minimumValue = num2;
    }
    return this.GetColorByRange(num, minimumValue, lowColor, maximumValue, highColor);
  }

  GetColorByRange(value, minValue, lowColor, maxValue, highColor) {
    let scale = (minValue != maxValue) ? ((value - minValue) / (maxValue - minValue)) : 1;
    let newA = this.GetScaledColorChanelValue(scale, lowColor.A, highColor.A);
    let newR = this.GetScaledColorChanelValue(scale, lowColor.R, highColor.R);
    let newG = this.GetScaledColorChanelValue(scale, lowColor.G, highColor.G);
    let newB = this.GetScaledColorChanelValue(scale, lowColor.B, highColor.B);
    let Obj = { A: newA, R: newR, G: newG, B: newB };
    return Obj;
  }
  GetScaledColorChanelValue(scale, lowChanel, highChanel) {
    return parseInt(lowChanel + (parseInt(highChanel) - parseInt(lowChanel)) * scale);
  }
  getDiff(t1, t2, gelen) {
    let donecek = moment.duration(moment(t1).diff(moment(t2)));
    return ((gelen == "Y") ? ("<b>Y: </b>") : ("<b>D: </b>")) + donecek;
  }
  getDiffGoal1(now, serviceRequest) {
    let devammi = serviceRequest.yanittarihi ? false : true; // Devam Ediyor : True
    let T0 = moment(serviceRequest.acilistarihi); // açılış tarihi
    let T = (devammi) ? moment(now) : moment(serviceRequest.yanittarihi); // true is şimdiyi al
    let TG = moment(serviceRequest.Goal1); // herzaman goal1 al
    let oncemi = moment.duration(T.diff(TG)).as('seconds') < 0;
    let renk = this.RenkGetir(T0.diff(T) / T0.diff(TG));
    serviceRequest["Emoji1"] = (devammi) ? ((oncemi) ? ('👍') : ('👎')) : ((oncemi) ? ('😊') : ('😔'));
    serviceRequest["Duration1"] = moment.duration(T0.diff(T)).locale('tr').humanize(false) + ((oncemi) ? ((devammi) ? (' süre geçti') : (' içinde cevap')) : ((devammi) ? (' Geçti') : (' Geçe Cevap')));;
    serviceRequest["Duration1_"] = moment.duration(T0.diff(TG)).locale('tr').humanize(false);
    serviceRequest["Renk1"] = { 'backgroundColor': renk };
    serviceRequest["Yanit"] = this.getDiff(T0, T, "Y");
    return serviceRequest;
  }
  getDiffGoal2(now, serviceRequest) {
    let devammi = serviceRequest.cozulmeTarihi ? false : true;
    let T0 = moment(serviceRequest.Goal1);
    let T = (devammi) ? moment(now) : moment(serviceRequest.cozulmeTarihi);
    let TG = moment(serviceRequest.Goal2);
    let oncemi = moment.duration(T.diff(TG)).as('seconds') < 0;
    let renk = this.RenkGetir(T0.diff(T) / T0.diff(TG));
    serviceRequest["warningColor"] = { 'color': renk };
    serviceRequest["HdsStateStyle3"] = {
      'borderColor': renk
    };
    serviceRequest["HdsStateStyle2"] = {
      'borderColor': "rgba(255,255,255, 0)" + renk + "rgba(255,255,255, 0) rgba(255,255,255, 0)",
      'width': 100 - serviceRequest["HdsState2"] + '%'
    };
    serviceRequest["HdsStateStyle"] = {
      'borderColor': renk,
      'backgroundColor': renk,
      'width': 100 - serviceRequest["HdsState2"] + '%'
    };
    serviceRequest["Emoji2"] = (devammi) ? ((oncemi) ? ('👍') : ('👎')) : ((oncemi) ? ('😊') : ('😔'));
    serviceRequest["Duration2"] = moment.duration(T.diff(TG)).locale('tr').humanize(false) + ((oncemi) ? ((devammi) ? (' Kaldı') : (' Kala Cevap')) : ((devammi) ? (' Geçti') : (' Geçe Cevap')));
    serviceRequest["Duration2_"] = moment.duration(T0.diff(TG)).locale('tr').humanize(false);
    serviceRequest["Renk2"] = { 'backgroundColor': renk };
    serviceRequest["Yanit"] = this.getDiff(T0, T, "Y");
    return serviceRequest;
  }
  getDynamicValues(serviceRequest) {
    var ola = "🔷";
    var sla = "🔶";
    for (let i = 0; i < serviceRequest.length; i++) {
      let j = 0;
      while (j < serviceRequest[i].Islemler.length) {
        if (serviceRequest[i].Islemler[j].EntityType !== 'HelpDeskFMS.Module.SE_Kisiyeata') {
          serviceRequest[i].Islemler.splice(j, 1);
          j--;
        }
        j++;
      }
      let maxTarih = Math.max.apply(Math, serviceRequest[i].Islemler.map(function (islem) { return new Date(islem.IslemTarihi).getTime(); }));
      let maxTarihIndex = serviceRequest[i].Islemler.findIndex(islem => new Date(islem.IslemTarihi).getTime() === maxTarih);
      if (maxTarihIndex > -1)
        serviceRequest[i].kisiyeAtamaAciklama = serviceRequest[i].Islemler[maxTarihIndex].Aciklama;
      serviceRequest[i].slaOla = sla;
      // if(serviceRequest[i].SLASTT===0){
      //   serviceRequest[i].slaOla=ola;
      // }
      // else if(serviceRequest[i].SLASTT===1){
      //   serviceRequest[i].slaOla=sla;
      // }
      serviceRequest[i]["Goruldu"] = serviceRequest[i]["Okundu"] == true ? 1 : 0;
      let progressRed = 0;
      let progressGreen = 180;

      serviceRequest[i]["HdsState2"] = (-serviceRequest[i]["HdsState"] * 100);
      if (serviceRequest[i]["HdsState2"] <= 0) {
        progressRed = 240;
        progressGreen = 0;
        serviceRequest[i]["HdsState2"] = 0;
      }
      if (serviceRequest[i]["HdsState2"] >= 100) {
        progressRed = 0;
        progressGreen = 180;
      }
      if (progressRed < 240 && serviceRequest[i]["HdsState2"] > 0 && serviceRequest[i]["HdsState2"] < 100) {
        progressGreen = 180;
        progressRed = (100 - serviceRequest[i]["HdsState2"]) * 3.6;
      }
      if (progressRed > 240 && progressGreen > 0 && serviceRequest[i]["HdsState2"] > 0 && serviceRequest[i]["HdsState2"] < 100) {
        progressRed = 240;
        progressGreen = (serviceRequest[i]["HdsState2"]) * 5.4;
      }
      let now = new Date(new Date().getTime() + 1000 * 60 * 60 * 3).toISOString().replace('Z', '');
      serviceRequest[i] = this.getDiffGoal1(now, serviceRequest[i]);
      serviceRequest[i] = this.getDiffGoal2(now, serviceRequest[i]);
      serviceRequest[i].KapatmaTuru = "Barkod";
      for (let j = 0; j < this.mymServiceList.length; j++) {
        if (serviceRequest[i].IlgiliServis) {
          if (serviceRequest[i].IlgiliServis.oid === this.mymServiceList[j].oid)
            serviceRequest[i].KapatmaTuru = this.mymServiceList[j].KapatmaTuru;
        }
      }
    }
  }

  numuneKontrol(samplePortage) {
    var farkliNumuneList = [];
    var teslimEdilmeyenList = [];
    var ayniNumuneList = [];
    var varMi = false;
    var list1 = samplePortage.LaboratuvarKabul;
    var list2 = samplePortage.PorterKabul;
    for (var i = 0; i < list1.length; i++) {
      for (var j = 0; j < list2.length; j++) {
        if (list1[i].BarkodNo === list2[j].BarkodNo) {
          samplePortage.PorterKabul[j].durum = true;
          varMi = true;
        }
      }
      if (varMi) {
        ayniNumuneList.push(list1[i]);
      }
      else {
        farkliNumuneList.push(list1[i]);
      }
      varMi = false;
    }
    var fark = samplePortage.PorterKabul.length - ayniNumuneList.length;
    samplePortage["emoji1"] = samplePortage.PorterKabul.length === ayniNumuneList.length ? '😊' : '😔';
    samplePortage["mesaj1"] = samplePortage.PorterKabul.length === ayniNumuneList.length ? 'Teslim Edildi.' : Math.abs(fark) + ' Numune Eksik';
    samplePortage["renk1"] = samplePortage.PorterKabul.length === ayniNumuneList.length ? '#66be7b' : '#ffc0c0';
    samplePortage["emoji2"] = farkliNumuneList.length > 0 ? '👎' : '👍';
    samplePortage["mesaj2"] = farkliNumuneList.length === 0 ? 'Fazla Numune Yok.' : farkliNumuneList.length + ' Numune Fazla';
    samplePortage["renk2"] = farkliNumuneList.length > 0 ? '#ffe0c0' : '#66be7b';
    samplePortage["farkliNumuneList"] = farkliNumuneList;
    samplePortage["ayniNumuneList"] = ayniNumuneList;
    return samplePortage;
  }

