	loadData(gorevAdi, istekTalepTuru, selectedButton, notif) {
		this.selectedButton = selectedButton
		this.content.scrollToTop(0).then(() => {
			if (this.oldIstekTalepTuru != istekTalepTuru || this.oldGorevAdi != gorevAdi || notif == true) {
				this.showDetay = false
				this.istekTalepTuru = istekTalepTuru
				this.oldIstekTalepTuru = istekTalepTuru
				this.gorevAdi = gorevAdi
				this.oldGorevAdi = gorevAdi
				this.shouldEnableScrolling = true
				this.getServiceRequest()
			}
		})
		//this.restartScreenPosition("0px","119px","46px","10px","0px");
	}

